const items = $input.all();

if (items.length === 0) {
    return { historialLectura: "system: Sin historial previo." };
}

let historial = "";

// 1️⃣ FUNCIÓN PARA FORMATEAR LA HORA (Extraída de message_time)
const formatTime = (item) => {
    const timeStr = item.json.message_time;
    if (!timeStr) return "[00:00]";

    const d = new Date(timeStr);
    // Formato [DD/MM HH:mm] para seguimiento de tickets que cruzan días
    return `[${d.getDate().toString().padStart(2, '0')}/${(d.getMonth() + 1).toString().padStart(2, '0')} ${d.getHours().toString().padStart(2, '0')}:${d.getMinutes().toString().padStart(2, '0')}]`;
};

// 2️⃣ PRESERVAR MENSAJES DE SISTEMA (DATOS DEL USUARIO/EMPRESA)
const mensajesSistema = items.filter(i => 
    (i.json.role || "").toLowerCase() === "system"
);

for (const msg of mensajesSistema) {
    historial += `SISTEMA ${formatTime(msg)}: ${msg.json.content}\n`;
}

// 3️⃣ FILTRO POR REINICIO O BORRADO (Lógica de limpieza)
let startIndex = 0;
for (let i = items.length - 1; i >= 0; i--) {
    const texto = (items[i].json.content || "").toLowerCase();
    if (
        texto.includes("reinicio") ||
        texto.includes("eliminado") ||
        texto.includes("borrado") ||
        texto.includes("limpiar chat")
    ) {
        startIndex = i + 1;
        break;
    }
}

let itemsFiltrados = items.slice(startIndex);

// Eliminar mensajes system del flujo para evitar duplicidad arriba
itemsFiltrados = itemsFiltrados.filter(i => 
    (i.json.role || "").toLowerCase() !== "system"
);

// Limitar a los últimos 30 mensajes para no saturar el contexto del LLM
const MAX_MENSAJES = 30;
const itemsRecientes = itemsFiltrados.slice(-MAX_MENSAJES);

// 4️⃣ CONSTRUIR HISTORIAL CON ROLES DE MESA DE AYUDA
for (const item of itemsRecientes) {
    const role = (item.json.role || "assistant").toLowerCase();
    const content = item.json.content || "[mensaje vacío]";
    const timeLabel = formatTime(item);

    if (role === "user") {
        historial += `CLIENTE ${timeLabel}: ${content}\n`;
    } else {
        historial += `SOPORTE ${timeLabel}: ${content}\n`;
    }
}

// Fallback por si el historial queda vacío tras los filtros
if (!historial.trim()) {
    historial = "SISTEMA: Chat iniciado. Sin mensajes previos relevantes.";
}

return {
    historialLectura: historial.trim()
};

